verb :object_match_failed(match_result, string) rxd {
  // LambdaCore $command_utils:object_match_failed (#219), faithfully
  // ported. Returns true iff the match was bad (and a message was told
  // to the actor); returns 0 (false) when match_result is a real,
  // valid object the caller can proceed with.
  //
  // Divergence (1): the original picks notify vs tell based on
  // `$perm_utils:controls(caller_perms(), player)`; woo's chat surface
  // is uniform — `tell(actor, …)` is the one durable-line API, and
  // `actor` is the calling player by substrate convention. So the
  // tell-vs-notify branch collapses to `tell(actor, …)`.
  if (match_result == $nothing) {
    tell(actor, "You must give the name of some object.");
    return true;
  }
  let q = str_char(34);
  // LambdaCore L4-5: a `#`-prefixed input (paste-back of an objref-
  // shaped id) gets a more specific error than the generic
  // "I see no … here." wording. Reachable from programmer/builder
  // paths that take raw paste-back IDs (e.g. `@set #obj_xxx.foo to 1`).
  // The check is on the input *string*, not the match_result, so
  // every failure path that sees `#xxx` (failed match, ambiguous
  // match, invalid match) reports the # form back. This matters for
  // direct utility callers who pass an explicit `#id` and a
  // pre-resolved `!valid` match — without the string-side check, the
  // later `!valid` branch would print to_string(match_result), which
  // for an ObjRef stores the bare id without the `#` prefix.
  let hash_input = false;
  if (typeof(string) == "string" && str_starts(string, "#")) { hash_input = true; }
  if (match_result == $failed_match) {
    if (hash_input) {
      tell(actor, string + " does not exist.");
    } else {
      tell(actor, "I see no " + q + string + q + " here.");
    }
    return true;
  }
  if (match_result == $ambiguous_match) {
    tell(actor, "I don't know which " + q + string + q + " you mean.");
    return true;
  }
  // Tombstoned, never-existed, or otherwise unresolvable id. Catalog code
  // that takes raw ObjRef-shaped strings (e.g. paste-back of a recycled
  // id) used to fall through here and proceed with a phantom object.
  // Mirror LambdaCore's last `elseif (!valid(match_result))` branch.
  if (!valid(match_result)) {
    if (hash_input) {
      tell(actor, string + " does not exist.");
    } else {
      tell(actor, to_string(match_result) + " does not exist.");
    }
    return true;
  }
  return false;
}

verb :names_of(objects) rx {
  // LambdaCore $string_utils:names_of (#20). Renders a list of objects
  // as `name1(#id1)   name2(#id2)` — three-space separator, paste-able
  // ids per the woo `#`/`$` convention so a reader can copy any single
  // identifier back into eval. LambdaCore emits `name(#123)` directly
  // because every id starts with `#`; woo prefixes `#` for ULIDs and
  // leaves corenames (`$wiz`) bare.
  //
  // Surface note: this verb is NOT direct_callable — calls flow only
  // through verb dispatch, which observes the calling verb's
  // caller_perms when reading `item.name`. A future refinement may
  // gate per-name reads on canReadProperty, but for now woocode
  // catalogs treat object names as conventionally public (the inherited
  // `name` property is defined with `r` perms in bootstrap), and an
  // explicit gate would only matter for objects whose owner downgraded
  // their own `name` perms below the default.
  if (typeof(objects) != "list") {
    return "";
  }
  let line = "";
  for item in objects {
    if (typeof(item) == "string" && valid(item)) {
      let s = item;
      if (!str_starts(s, "$")) { s = "#" + s; }
      line = line + item.name + "(" + s + ")   ";
    }
  }
  return str_trim(line);
}

verb :to_value(s) rxd {
  // LambdaCore $string_utils:to_value (#20). Best-effort parse of a
  // user-typed value: returns [ok, value] so callers can detect parse
  // failure without try/catch. Used by @set / @property for the
  // `to <value>` tail.
  //
  // Initial port covers strings (quoted, balanced), integers, floats,
  // and objref literals (`#xxx` strips the prefix to the underlying
  // ObjRef; `$xxx` is returned verbatim because woo stores corenames
  // *as* the ObjRef). Lists, maps, and error literals are not yet
  // supported and explicitly rejected; LambdaCore's full
  // `$string_utils:value_to_literal` recursive-descent parser lands
  // incrementally.
  //
  // Divergence (1): LambdaCore returns failure for any malformed
  // literal. woo retains a bare-unquoted-text fallback as a chat-driven
  // authoring convenience — `@property obj.title hello` stores
  // `"hello"` rather than erroring. This is a Woo extension over
  // LambdaCore semantics.
  //
  // Divergence (2): inputs that *look like* a literal shape (start
  // with `"`, `{`, `[`, `#`) are required to fully parse. An input
  // like `"unterminated` (open quote, no close) or `{1, 2` (list
  // start without close) returns failure rather than falling through
  // to the bare-string Woo extension. Without this, the divergence-1
  // fallback would silently swallow malformed literal-shaped typos.
  if (typeof(s) != "string") { return [false, "not a string"]; }
  let trimmed = str_trim(s);
  let n = length(trimmed);
  if (n == 0) { return [false, "empty value"]; }
  let first = str_slice(trimmed, 1, 1);
  let quote = str_char(34);
  // Quoted string: open quote requires a matching close quote at the
  // end; otherwise the literal is malformed.
  if (first == quote) {
    if (n >= 2) {
      if (str_slice(trimmed, n, n) == quote) {
        return [true, str_slice(trimmed, 2, n - 1)];
      }
    }
    return [false, "unterminated string literal"];
  }
  // List/map literals — not yet ported. Reject so a stray `{` doesn't
  // round-trip as a bare string.
  if (first == "{") { return [false, "list literals not yet supported in to_value"]; }
  if (first == "[") { return [false, "map literals not yet supported in to_value"]; }
  // Objref literal: `#xxx` evaluates to the underlying ObjRef. The
  // dsl-compiler does the same for `#`-prefixed literals in eval.
  // Require a non-empty body and no embedded whitespace; otherwise
  // it's a malformed literal, not a bare string.
  if (first == "#") {
    if (n < 2) { return [false, "malformed objref literal: " + trimmed]; }
    if (str_index(trimmed, " ") > 0) { return [false, "malformed objref literal: " + trimmed]; }
    return [true, str_slice(trimmed, 2)];
  }
  // Corename literal: `$wiz` IS the ObjRef in woo. Require contiguous
  // corename; embedded whitespace flags a malformed literal.
  if (first == "$") {
    if (str_index(trimmed, " ") > 0) { return [false, "malformed corename: " + trimmed]; }
    return [true, trimmed];
  }
  // Integer (round-trips through to_string).
  let as_int = to_int(trimmed);
  if (to_string(as_int) == trimmed) { return [true, as_int]; }
  // Float (round-trips through to_string).
  let as_float = to_float(trimmed);
  if (to_string(as_float) == trimmed) { return [true, as_float]; }
  // Fall back to the bare string (Woo extension — see Divergence (1)).
  return [true, trimmed];
}

verb :parse_propref(string) rxd {
  // LambdaCore $code_utils:parse_propref (#153). Splits `<obj>.<prop>`
  // (or bare `$prop` against `$system`) into [obj_str, prop_str], or
  // returns false on parse failure. The obj_str is left as-typed so
  // the caller does its own resolution via $match:match_object.
  //
  // Divergence (1): LambdaCore returns `{"#0", prop}` for the bare
  // `$foo` case (treating it as `$system.foo`). woo uses `$system`
  // verbatim — same intent, woo-shaped corename.
  //
  // Divergence (2): LambdaCore L9-13 looks up `$xxx` against #0
  // (returning false if the property is missing or not an object).
  // woo treats `$xxx` as the ObjRef directly via the substrate's
  // corename map; we mirror the validation by calling valid($xxx) —
  // a non-existent corename returns false rather than handing back a
  // dangling ref.
  if (typeof(string) != "string") { return false; }
  let s = string;
  let dot = str_index(s, ".");
  if (dot > 0) {
    let object = str_slice(s, 1, dot - 1);
    let prop = str_slice(s, dot + 1);
    if (object == "" || prop == "") { return false; }
    if (str_starts(object, "$") && !valid(object)) { return false; }
    return [object, prop];
  }
  if (str_starts(s, "$")) {
    return ["$system", str_slice(s, 2)];
  }
  return false;
}

verb :parse_verbref(string) rxd {
  // LambdaCore $code_utils:parse_verbref (#153). Splits `<obj>:<verb>`
  // into [obj_str, verb_name], or returns false on parse failure.
  // Used by @verb / @args / @rmverb / @list / @rename to extract the
  // pieces; obj_str is handed verbatim to $match:match_object.
  //
  // Divergence (1): LambdaCore resolves $-prefixed objects to #N via
  // properties of #0 and returns tostr(#N). woo's corenames ARE the
  // ObjRef, so `$wiz:foo` returns ["$wiz", "foo"] verbatim — the caller
  // hands that to $match:match_object which already accepts $/# prefixes.
  //
  // Divergence (2): same as parse_propref — a $xxx that doesn't resolve
  // returns false rather than handing back a dangling ref. `#xxx` is
  // not validated here (the caller's match_object catches it).
  if (typeof(string) != "string") { return false; }
  let s = string;
  let colon = str_index(s, ":");
  if (colon == 0) { return false; }
  let object = str_slice(s, 1, colon - 1);
  let verbname = str_slice(s, colon + 1);
  if (object == "" || verbname == "") { return false; }
  if (str_starts(object, "$") && !valid(object)) { return false; }
  return [object, verbname];
}

verb :parse_argspec(tokens) rxd {
  // LambdaCore $code_utils:parse_argspec (#153). Parses the leading
  // dobj/prep/iobj specifier off a list of word tokens and returns
  // [verb_args, remaining_args] on success or a string error message.
  // `verb_args` is variable length depending on what tokens were given:
  //   []                           — no specifier
  //   ["this","none","this"]       — "tnt" shortcut
  //   [dobj]                       — only direct-object specifier given
  //   [dobj, prep]                 — direct + preposition only
  //   [dobj, prep, iobj]           — full spec (the common case)
  // Callers that need a fully-padded spec (e.g. @verb) pad missing
  // slots with "none" themselves.
  //
  // Divergence (1): LambdaCore consults $code_utils._short_preps /
  // _other_preps / _multi_preps for multi-word prepositions ("in front
  // of", "on top of"). The initial port carries only the single-word
  // prep table from woo's command-parser (src/core/world.ts
  // PREPOSITIONS); a typed `@verb obj:foo this in front of any` returns
  // an error and the user can fall back to `in`. Multi-word lookup can
  // land when a verb here needs it.
  if (typeof(tokens) != "list") { return "parse_argspec expects a list of tokens"; }
  let n = length(tokens);
  if (n < 1) { return [[], []]; }
  let ds = tokens[1];
  let q = str_char(34);
  if (ds == "tnt") {
    let tnt_rest = [];
    if (n > 1) { for i in [2..n] { tnt_rest = tnt_rest + [tokens[i]]; } }
    return [["this", "none", "this"], tnt_rest];
  }
  let is_dobj = false;
  if (ds == "this") { is_dobj = true; }
  if (ds == "any") { is_dobj = true; }
  if (ds == "none") { is_dobj = true; }
  if (!is_dobj) {
    return q + ds + q + " is not a valid direct object specifier.";
  }
  if (n < 2) { return [[ds], []]; }
  let prep_tok = tokens[2];
  let verbargs = [];
  let rest_start = 3;
  let prep_ok = false;
  if (prep_tok == "none") { prep_ok = true; }
  if (prep_tok == "any") { prep_ok = true; }
  if (!prep_ok) {
    let single_preps = ["with", "using", "at", "to", "in", "inside", "into", "on", "upon", "as", "from", "over", "through", "under", "underneath", "behind", "beside", "for", "about", "off"];
    for p in single_preps { if (p == prep_tok) { prep_ok = true; } }
    if (!prep_ok) {
      return q + prep_tok + q + " is not a valid preposition.";
    }
  }
  verbargs = [ds, prep_tok];
  if (n >= rest_start) {
    verbargs = verbargs + [tokens[rest_start]];
    rest_start = rest_start + 1;
  }
  let rest = [];
  if (n >= rest_start) { for i in [rest_start..n] { rest = rest + [tokens[i]]; } }
  if (length(verbargs) >= 3) {
    let io = verbargs[3];
    let is_iobj = false;
    if (io == "this") { is_iobj = true; }
    if (io == "any") { is_iobj = true; }
    if (io == "none") { is_iobj = true; }
    if (!is_iobj) {
      return q + io + q + " is not a valid indirect object specifier.";
    }
  }
  return [verbargs, rest];
}

verb :toint(s) rxd {
  // LambdaCore $code_utils:toint (#153), faithfully ported. Mirrors
  // `match(s, "^ *[-+]?[0-9]+ *$") ? toint(s) | E_TYPE`. Returns the
  // integer on a clean parse, otherwise false.
  //
  // Divergence (1): LambdaCore returns E_TYPE on parse failure. woo
  // returns `false` — DSL-friendly because callers can
  // `if (typeof(result) == "number")` to test, no try/catch needed.
  // Callers reaching for the LambdaCore wording can wrap a raise
  // around the false return.
  //
  // The pre-1.0 port used to_string round-trip, which rejected
  // LambdaCore-valid forms like `01`, `000`, and `-0`. The current
  // implementation does the regex-equivalent character walk so woo's
  // toint matches LambdaCore's set of accepted strings exactly.
  if (typeof(s) != "string") { return false; }
  let trimmed = str_trim(s);
  let len = length(trimmed);
  if (len == 0) { return false; }
  let i = 1;
  let first = str_slice(trimmed, 1, 1);
  if (first == "+") { i = 2; }
  if (first == "-") { i = 2; }
  if (i > len) { return false; }
  while (i <= len) {
    let c = str_slice(trimmed, i, i);
    if (str_index("0123456789", c) == 0) { return false; }
    i = i + 1;
  }
  let parsed = to_int(trimmed);
  // Normalize negative zero. JS coerces "-0" to a distinct -0 number;
  // LambdaCore's MOO INT has no signed zero, so toint("-0") returns 0.
  if (parsed == 0) { return 0; }
  return parsed;
}

verb :nth_verb_name(obj, n) rxd {
  // 1-indexed Nth own verb name on `obj`, or false if out of range.
  // Used to translate LambdaCore's verb-by-number form (`@args#1`,
  // `@rmverb#3`, `@list obj:2`) into a name woo's substrate can
  // address. verb_info also accepts integers, but consistently
  // resolving to a name simplifies downstream display and error paths.
  if (typeof(n) != "number") { return false; }
  let names = verbs(obj);
  if (n < 1 || n > length(names)) { return false; }
  return names[n];
}
